 20	import TreeTableBody from './components/TreeTableBody/TreeTableBody';
 21	import TreeToolbar from './components/TreeToolbar/TreeToolbar';
 22	import usePagination from './hooks/usePagination/usePagination';
 23	import { useTreeFilterAttributes } from './hooks/useTreeFilterAttributes';
 24	import useTreePagination from './hooks/useTreePagination';
 25	import { useTreeRows } from './hooks/useTreeRows';
 26	import useTreeSortBlocks from './hooks/useTreeSortBlocks';
 27	import useTreeFilters from './hooks/useTreeVMFilters';
 28	import { getVmRowsId } from './hooks/utils/treeUtils';
 29	import { defaultColumns } from './utils/constants';
 30	import type { VmRow } from './utils/types';
 31	
 32	type VsphereFolderTreeTableProps = {
 33	  initialSelectedIds: string[] | undefined;
 34	  onSelect: ((selectedVMs: VmData[] | undefined) => void) | undefined;
 35	  vmData: VmData[] | undefined;
 36	  foldersDict: Record<string, VSphereResource>;
 37	  hostsDict: Record<string, ProviderHost>;
 38	};
 39	
 40	const VsphereFolderTreeTable: FC<VsphereFolderTreeTableProps> = ({
 41	  foldersDict,
 42	  hostsDict,
 43	  initialSelectedIds,
 44	  onSelect,
 45	  vmData,
 46	}) => {
 47	  const { t } = useForkliftTranslation();
 48	  const [columns, setColumns] = useState<ResourceField[]>(defaultColumns);
 49	  const visibleVmIdsRef = useRef<Set<string> | undefined>(undefined);
 50	
 51	  const setSelectedVmKeysControlled = useCallback(
 52	    (ids: string[]) => {
 53	      const set = new Set(ids);
 54	      const selected = vmData?.filter((data) => set.has(data.vm.id));
 55	      onSelect?.(selected);
 56	    },
 57	    [vmData, onSelect],
 58	  );
 59	
 60	  const canSelect = initialSelectedIds !== undefined;
 61	  const { groupVMCountByFolder, rows, selectedVmKeys, setSelectedVmKeys, setShowAll, showAll } =
 62	    useTreeRows({
 63	      ...(initialSelectedIds
 64	        ? {
 65	            controls: {
 66	              selectedVmKeys: initialSelectedIds,
 67	              setSelectedVmKeys: setSelectedVmKeysControlled,
 68	            },
 69	          }
 70	        : undefined),
 71	      canSelect,
 72	      foldersDict,
 73	      hostsDict,
 74	      visibleVmIdsRef,
 75	      vmDataArr: vmData,
 76	    });
 77	
 78	  const {
 79	    onPerPageSelect,
 80	    onSetPage,
 81	    pagination: { page, perPage },
 82	  } = usePagination();
 83	
 84	  const attributes = useTreeFilterAttributes(rows);
 85	  const filters = useAttributeFilters<VmRow>(attributes);
 86	
 87	  const { filteredGroupVMCountByFolder, filteredRows, visibleVmIds } = useTreeFilters({
 88	    filters,
 89	    rows,
 90	    showAll,
 91	  });
 92	
 93	  visibleVmIdsRef.current = filters.hasAttrFilters || !showAll ? visibleVmIds : undefined;
 94	
 95	  const { handleOnSort, sortBy, sortedBlocks, visibleCols } = useTreeSortBlocks({
 96	    columns,
 97	    filteredRows,
 98	  });
 99	
100	  const { itemCount, pagedRows } = useTreePagination({ blocks: sortedBlocks, page, perPage });
101	
102	  useEffect(() => {
103	    // if page > max pages after filter/sort, snap back
104	    const maxPage = Math.max(1, Math.ceil(itemCount / perPage));
105	    if (page > maxPage) onSetPage({} as MouseEvent, 1);
106	  }, [itemCount, onSetPage, page, perPage]);
107	
108	  const pagination = (
109	    <ToolbarItem variant="pagination">
110	      <Pagination
111	        page={page}
112	        onSetPage={onSetPage}
113	        onPerPageSelect={onPerPageSelect}
114	        itemCount={itemCount}
115	        perPage={perPage}
116	      />
117	    </ToolbarItem>
118	  );
119	
120	  return (
121	    <PageSection variant={PageSectionVariants.light}>
122	      {!canSelect && <SectionHeading text={t('Virtual machines')} />}
123	      <TreeToolbar
124	        attributes={attributes}
125	        canSelect={canSelect}
126	        columns={columns}
127	        dataIds={getVmRowsId(rows)}
128	        onSelect={(selectIds) => {
129	          setSelectedVmKeys(selectIds);
130	          if (!showAll && isEmpty(selectIds)) {
131	            setShowAll(true);
132	          }
133	        }}
134	        pageDataIds={getVmRowsId(pagedRows)}
135	        selectedVmKeys={selectedVmKeys}
136	        filters={filters}
137	        pagination={pagination}
138	        setColumns={setColumns}
139	        setShowAll={setShowAll}
140	        showAll={showAll}
141	      />
142	      <Table isTreeTable data-testid="vsphere-tree-table">
143	        <Thead>
144	          <Tr>
145	            {visibleCols.map((col, idx) => (
146	              <Th key={col.id} sort={{ columnIndex: idx, onSort: handleOnSort, sortBy }}>
147	                {col.label}
148	              </Th>
149	            ))}
150	          </Tr>
151	        </Thead>
152	        <TreeTableBody
153	          clearAllFilters={filters.clearAll}
154	          columns={columns}
155	          groupVMCountByFolder={
156	            filters.hasAttrFilters ? filteredGroupVMCountByFolder : groupVMCountByFolder
157	          }
158	          hasFiltersApplied={filters.hasAttrFilters}
159	          pagedRows={pagedRows}
160	          showAll={showAll}
161	        />
162	      </Table>
163	      <Toolbar>
164	        <ToolbarContent>{pagination}</ToolbarContent>
165	      </Toolbar>
166	    </PageSection>
167	  );
168	};
169	
170	export default VsphereFolderTreeTable;

